            padding: 15px;
            margin: 15px 0;
            border-radius: 4px;
        }
    </style>
</head>
<body>
    <div class="header">
        <h1>📊 INFORME DIARIO DE COBRANZAS</h1>
        <h2>Plan de Ahorro Óvalo</h2>
