        </div>
        <div class="card info">
            <div class="card-title">📊 Tasa de Éxito</div>
            <div class="card-value">${tasaExito}%</div>
        </div>
    </div>

    ${montoTotalDeuda > 0 ? `
    <div class="highlight-box">
        <strong>💰 Monto Total de Deuda Contactada:</strong> ${montoTotalDeuda.toLocaleString('es-AR', { style: 'currency', currency: 'ARS' })}
    </div>
    ` : ''}

    <div class="section">
        <h2>📈 Distribución por Tipo de Cliente</h2>
        <table>
            <tr>
                <th>Tipo</th>
                <th>Cantidad</th>
                <th>Porcentaje</th>
                <th>Descripción</th>
            </tr>
            ${tipo2 > 0 ? `
            <tr>
                <td><strong>Tipo 2</strong></td>
                <td>${tipo2}</td>
                <td>${totalRegistros > 0 ? ((tipo2/totalRegistros)*100).toFixed(1) : 0}%</td>
                <td>Ahorrista Libre de Deuda</td>
            </tr>
            ` : ''}
            ${tipo3 > 0 ? `
            <tr>
                <td><strong>Tipo 3</strong></td>
                <td>${tipo3}</td>
