                <td>Ahorrista Moroso (más de 1 cuota impaga)</td>
            </tr>
            ` : ''}
            ${tipo5 > 0 ? `
            <tr>
                <td><strong>Tipo 5</strong></td>
                <td>${tipo5}</td>
                <td>${totalRegistros > 0 ? ((tipo5/totalRegistros)*100).toFixed(1) : 0}%</td>
                <td>Adjudicado Definitivo en Mora</td>
            </tr>
            ` : ''}
        </table>
    </div>

    ${Object.keys(provincias).length > 0 ? `
    <div class="section">
        <h2>🗺️ DISTRIBUCIÓN POR PROVINCIA</h2>
