            <tr>
                <th>Provincia</th>
                <th>Total</th>
                <th>Exitosos</th>
                <th>Fallidos</th>
                <th>Tasa Éxito</th>
            </tr>
            ${Object.entries(provincias).map(([prov, data]) => `
                <tr>
                    <td><strong>${prov}</strong></td>
                    <td>${data.total}</td>
                    <td style="color: #28a745; font-weight: bold;">${data.exitosos}</td>
                    <td style="color: #dc3545; font-weight: bold;">${data.fallidos}</td>
                    <td>${data.total > 0 ? ((data.exitosos/data.total)*100).toFixed(1) : 0}%</td>
                </tr>
            `).join('')}
        </table>
    </div>
    ` : ''}

    ${clientesExitosos.length > 0 ? `
