        <h2>✅ CLIENTES CONTACTADOS EXITOSAMENTE (${clientesExitosos.length})</h2>
        <table>
            <tr>
                <th>Cliente</th>
                <th>Grupo/Orden</th>
                <th>Tipo</th>
                <th>Cuotas Imp.</th>
