                <th>Teléfono</th>
                <th>Hora</th>
            </tr>
            ${clientesExitosos.map(c => {
              const montoStr = String(c.montoDeuda).replace(',', '.');
              const monto = parseFloat(montoStr);
              const montoFormateado = isNaN(monto) ? 'N/A' : monto.toLocaleString('es-AR', { style: 'currency', currency: 'ARS' });

              // Clase CSS según tipo
              let claseTipo = 'status-success';
              if (c.tipoNumerico === 2) claseTipo = 'status-tipo2';
              else if (c.tipoNumerico === 3) claseTipo = 'status-tipo3';
              else if (c.tipoNumerico === 5) claseTipo = 'status-tipo5';

              return `
                <tr>
                    <td><strong>${c.nombre}</strong></td>
                    <td>${c.grupo}/${c.orden}</td>
                    <td><span class="status-badge ${claseTipo}">${c.estado}</span></td>
                    <td>${c.cuotasImpagas}</td>
                    <td>${montoFormateado}</td>
                    <td>${c.ciudad}, ${c.provincia}</td>
                    <td>${c.telefono}</td>
                    <td>${c.horaEnvio}</td>
