      montoTotalDeuda: montoTotalDeuda,
      tipo2: tipo2,
      tipo3: tipo3,
      tipo5: tipo5
    },
    provincias: provincias,
    fechaReporte: fechaHoy,
    horaReporte: horaReporte,
    clientesExitosos: clientesExitosos,
    clientesConProblemas: clientesConProblemas
  }
}];

// Nodo Code para TIPO 3 - AHORRISTA MOROSOS (2 o más cuotas impagas)
const datos_personales = $('match_data').first().json;
const datos_plan = $('Loop Deudores').first().json;
const modelo_vehiculo = $('match_modelo').first().json.Descripcion ? $('match_modelo').first().json.Descripcion : datos_personales.Modelo;
const monto_deuda = $('Loop Deudores').first().json["Monto Próxima Cuota"];
const fecha_vencimiento = $('Loop Deudores').first().json["Fecha Vencimiento Próxima Cuota"];
const cuotas_impagas = $('Loop Deudores').first().json["Cuotas Impagas"] || 2;
let asunto = "";

if(datos_plan.test_mail){
  datos_personales.mail = datos_plan.test_mail
}

// Obtener fecha y hora actuales
const ahora = new Date();
const fecha = ahora.toLocaleDateString('es-AR'); // formato DD/MM/AAAA
const hora = ahora.toLocaleTimeString('es-AR');  // formato HH:MM:SS

// Formatear fecha de vencimiento a DD-MM-YYYY
function formatearFecha(fechaStr) {
  if (!fechaStr) return '';

  // Si ya viene en formato DD/MM/YYYY o DD-MM-YYYY
  if (fechaStr.includes('/') || fechaStr.includes('-')) {
    const partes = fechaStr.split(/[\/\-]/);
    if (partes.length === 3) {
      return `${partes[0].padStart(2, '0')}-${partes[1].padStart(2, '0')}-${partes[2]}`;
    }
  }

  return fechaStr;
}

const fecha_formateada = formatearFecha(fecha_vencimiento);

asunto = `Aviso Importante - Plan Óvalo (Grupo ${datos_plan['ID Grupo']} / Orden ${datos_plan["Número Orden"]})`;

const mensaje = `
